function hr_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function hr_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;} function hr_c($v){return strtoupper(trim((string)$v));} function hr_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
