function hr_next_no($year){global $db;$year=(int)$year>0?(int)$year:(int)date('Y');$r=$db->fetch("SELECT hiring_no FROM erp_hiring WHERE hiring_no LIKE ? ORDER BY hiring_no DESC LIMIT 1",array('HIR-'.$year.'-%'));$n=1;if($r&&preg_match('/-(\d+)$/',$r->hiring_no,$m))$n=(int)$m[1]+1;return 'HIR-'.$year.'-'.str_pad($n,3,'0',STR_PAD_LEFT);}
function hr_row($id){global $db;return $db->fetch("SELECT h.*,s.selection_no,s.decision_result,a.applicant_no,a.applicant_name,a.applicant_status,v.vacancy_no,v.vacancy_title,emp.employee_no hired_no,emp.full_name hired_name,pos.position_code,pos.position_name,jt.job_title_code,jt.job_title_name,rec.employee_no recruiter_no,rec.full_name recruiter_name,hm.employee_no manager_no,hm.full_name manager_name,pic.employee_no pic_no,pic.full_name pic_name FROM erp_hiring h LEFT JOIN erp_selection_result s ON s.id=h.selection_result_id LEFT JOIN erp_applicant_data a ON a.id=h.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=h.vacancy_id LEFT JOIN erp_employee_master emp ON emp.id=h.hired_employee_id LEFT JOIN erp_position pos ON pos.id=h.proposed_position_id LEFT JOIN erp_job_title jt ON jt.id=h.proposed_job_title_id LEFT JOIN erp_employee_master rec ON rec.id=h.recruiter_employee_id LEFT JOIN erp_employee_master hm ON hm.id=h.hiring_manager_employee_id LEFT JOIN erp_employee_master pic ON pic.id=h.hr_pic_employee_id WHERE h.id=? LIMIT 1",array((int)$id));}
