function hr_sync($hiringId){global $db;$h=hr_row($hiringId);if(!$h)return;if(in_array($h->hiring_status,array('HIRED','ONBOARDED'),true)){$db->update('erp_applicant_data',array('applicant_status'=>'HIRED','hired_employee_id'=>$h->hired_employee_id?:null,'updated_by'=>'admin','updated_at'=>date('Y-m-d H:i:s')),'id',(int)$h->applicant_id);}elseif(!in_array($h->hiring_status,array('CANCELLED','DECLINED'),true)){$db->update('erp_applicant_data',array('applicant_status'=>'OFFER','updated_by'=>'admin','updated_at'=>date('Y-m-d H:i:s')),'id',(int)$h->applicant_id);}if((int)$h->vacancy_id>0){$c=$db->fetch("SELECT SUM(hiring_status IN ('HIRED','ONBOARDED')) hired_count,SUM(offer_status IN ('SENT','NEGOTIATION','ACCEPTED')) offer_count FROM erp_hiring WHERE vacancy_id=?",array((int)$h->vacancy_id));$db->query("UPDATE erp_job_vacancy SET hired_count=?,offer_count=?,vacancy_status=CASE WHEN ?>=headcount_approved AND headcount_approved>0 THEN 'HIRED' WHEN ?>0 THEN 'OFFER' ELSE vacancy_status END,updated_by='admin',updated_at=NOW() WHERE id=?",array((int)$c->hired_count,(int)$c->offer_count,(int)$c->hired_count,(int)$c->offer_count,(int)$h->vacancy_id));}}
